// Construit le brief structuré + le payload Anthropic complet, prêt à être envoyé.

const params = $('Paramètres OCC').first().json;
const pre = $('Audit (pré-rapprochement)').first().json;
const rap = $('Rapprocher (intelligent)').first().json;
const post = $('Audit (post-rapprochement)').first().json;

function trimAudit(a) {
  if (!a) return null;
  return {
    societe: a.societe,
    comptes_bancaires: (a.comptes_bancaires || []).map(c => ({
      banque: c.banque,
      numero_compte: c.numero_compte,
      devise: c.devise,
      compte_comptable: c.compte_comptable,
      solde_actuel: c.solde_actuel,
      solde_dernier_releve: c.solde_dernier_releve,
      date_dernier_releve: c.date_dernier_releve,
    })),
    releves: a.releves,
    transactions: {
      total: a.transactions?.total,
      rapprochees: a.transactions?.rapprochees,
      classifiees_seulement: a.transactions?.classifiees_seulement,
      orphelines: a.transactions?.orphelines,
      taux_rapprochement_pct: a.transactions?.taux_rapprochement_pct,
      orphelines_echantillon: (a.transactions?.orphelines_echantillon || []).slice(0, 15),
    },
    factures: {
      total: a.factures?.total,
      par_statut: a.factures?.par_statut,
      impayees: a.factures?.impayees,
      impayees_montant_mur: a.factures?.impayees_montant_mur,
      impayees_echantillon: (a.factures?.impayees_echantillon || []).slice(0, 15),
    },
    plan_comptable_top: (a.plan_comptable_utilisation || []).slice(0, 10),
  };
}

const diff = {
  taux_rapprochement_pre_pct: pre?.transactions?.taux_rapprochement_pct ?? null,
  taux_rapprochement_post_pct: post?.transactions?.taux_rapprochement_pct ?? null,
  delta_rapprochees: (post?.transactions?.rapprochees ?? 0) - (pre?.transactions?.rapprochees ?? 0),
  delta_orphelines: (post?.transactions?.orphelines ?? 0) - (pre?.transactions?.orphelines ?? 0),
};

const brief = {
  societe: { id: params.societe_id, nom: params.societe_nom },
  generated_at: new Date().toISOString(),
  pre: trimAudit(pre),
  post: trimAudit(post),
  diff,
  rapprochement: {
    stats: rap?.stats,
    period: rap?.period,
    fx_rates_used: rap?.fx_rates_used,
    writes: rap?.writes,
    matches: (rap?.matches || []).slice(0, 30).map(m => ({
      tx: m.transactionKey,
      libelle: m.transaction?.libelle,
      debit: m.transaction?.debit,
      credit: m.transaction?.credit,
      devise: m.transaction?.devise,
      strategy: m.strategy,
      confidence: m.confidence,
      reasoning: m.reasoning,
      facture_ids: m.factureIds,
      amount_diff: m.amountDiff,
    })),
    classifications: (rap?.classifications || []).slice(0, 30),
  },
};

const systemPrompt = [
  "Tu es un expert-comptable mauricien spécialisé en IFRS et plan comptable mauricien (PCM).",
  "Tu reçois un brief JSON décrivant un cycle de rapprochement bancaire qui vient d'être exécuté pour une société.",
  "Produis un RAPPORT en français, structuré et exploitable, à destination du comptable en charge.",
  "",
  "Format strict (markdown) :",
  "",
  "# Rapport de rapprochement — <nom société>",
  "",
  "## 1. Résumé exécutif",
  "3 phrases max : santé du rapprochement, gain de cette exécution, prochaine action prioritaire.",
  "",
  "## 2. Comptes bancaires",
  "Table : banque | n° | devise | compte PCM | dernier solde | date.",
  "",
  "## 3. Avant / après",
  "Table comparative : tx totales / rapprochées / orphelines / taux %.",
  "",
  "## 4. Matches détectés",
  "Pour chaque match (limite 10 plus pertinents) : libellé tx, montant + devise, stratégie, confiance, factures rapprochées, justification courte.",
  "",
  "## 5. Tx orphelines à examiner",
  "Pour les 5 plus gros montants non rapprochés : libellé, montant, devise, hypothèses (frais bancaire ? virement interne ? acompte ?), proposition de classement PCM (compte 4-digits).",
  "",
  "## 6. Risques détectés",
  "Écarts de change suspects, factures impayées de plus de 60 jours, comptes 411x/401x non lettrés inhabituels, anomalies de devise/montant.",
  "",
  "## 7. Actions recommandées",
  "Liste numérotée et priorisée (5 max), chaque action concrète et actionnable dans la semaine.",
  "",
  "Ne JAMAIS inventer de chiffres : si une donnée manque, écris '— donnée non disponible'. Sois concis, factuel, professionnel. Pas d'emoji.",
].join('\n');

const userText = 'Voici le brief JSON du cycle de rapprochement à analyser :\n\n```json\n' + JSON.stringify(brief, null, 2) + '\n```';

const anthropic_payload = {
  model: 'claude-sonnet-4-6',
  max_tokens: 4096,
  system: systemPrompt,
  messages: [
    { role: 'user', content: userText }
  ],
};

return { json: { brief, diff, anthropic_payload } };
